const axios = require('axios');
const GenericResource = require('../lib/generic-resource');
const constants = require('../lib/constants');

jest.mock('axios',()=>{
    return {
        defaults: {headers: {
                     common: {}   
        }},
        post: (url,data)=>{
            return Promise.resolve(data);
        },
        delete: (url)=>{
            let el = url.split('/');
            let response = {
                deleted: true,
                id: el[el.length -1]
            }
            return Promise.resolve(response);
        },
        get: (url)=>{
            let response = {};
            let el = url.split('/');

            if(el.length > 2){
                response.id = el[el.length -1];
            } else {
                response.object = 'list';
                response.hasMore = false;
                response.totalCount = 2;
                response.limit = 10;
                response.offset = 0;
                response.data = [
                    {
                        id: 'cus_123'
                    },
                    {
                        id: 'cus_456'
                    }
                ];
            }

            return Promise.resolve(response);
        }
    }
});

test('Config padrão', ()=>{
    const configFn = (o)=>{
        return o;
    }

    let genericRes = new GenericResource(configFn);

    expect(genericRes._configFn).toEqual(configFn);
    expect(genericRes.config).toEqual({});
    expect(genericRes.resource).toBe('');
});

test('Configuração de Produção', ()=>{
    const configFn = ()=>{
        return {
            environment: constants.PRODUCTION,
            apiKey: 'Chave_Producao',
            version: 'v3'
        }
    };

    let genericRes = new GenericResource(configFn);
    genericRes.loadConfig();

    expect(axios.defaults.baseURL).toBe('https://www.asaas.com/api/v3');
    expect(axios.defaults.headers.common['access_token']).toBe('Chave_Producao');
    expect(axios.defaults.headers.common['Content-Type']).toBe('application/json');
});

