test('Enviando Post', async ()=>{
    const configFn = ()=>{
        return {
            environment: constants.SANDBOX,
            apiKey: 'Chave_Sandbox',
            version: 'v3'
        }
    };

    let genericRes = new GenericResource(configFn);

    let cliente = {
        cpfCnpj: '12345678901',
        name: 'José da Silva'
    };

    genericRes.resource = '/customers';

    await expect(genericRes.post(cliente)).resolves.toEqual(cliente);
    expect(axios.defaults.baseURL).toBe('https://sandbox.asaas.com/api/v3');
    expect(axios.defaults.headers.common['access_token']).toBe('Chave_Sandbox');
    expect(axios.defaults.headers.common['Content-Type']).toBe('application/json');
});

