test('Obtendo uma lista de registros', async ()=>{
    const configFn = ()=>{
        return {
            environment: constants.SANDBOX,
            apiKey: 'Chave_Sandbox',
            version: 'v3'
        }
    };

    let genericRes = new GenericResource(configFn);

    genericRes.resource = '/customers';

    let params = {
        offset: 0,
        limit: 10
    }

    let response = {};
    response.object = 'list';
    response.hasMore = false;
    response.totalCount = 2;
    response.limit = 10;
    response.offset = 0;
    response.data = [
        {
            id: 'cus_123'
        },
        {
            id: 'cus_456'
        }
    ];

    await expect(genericRes.list(params)).resolves.toEqual(response);
});

